const config = {
  "previewFeatures": [],
  "clientVersion": "7.4.0",
  "engineVersion": "ab56fe763f921d033a6c195e7ddeb3e255bdbb57",
  "activeProvider": "postgresql",
  "inlineSchema": "enum Site_type {\n  LHS\n  RHS\n  BHS\n}\n\nmodel DPR {\n  id Int @id @default(autoincrement())\n\n  date         DateTime\n  project_id   Int\n  submitted_by Int\n\n  project Project       @relation(fields: [project_id], references: [id], onDelete: Cascade)\n  user    User          @relation(fields: [submitted_by], references: [id], onDelete: Cascade)\n  entries DPRChainage[]\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  @@index([project_id])\n  @@index([date])\n  @@map(\"dprs\")\n}\n\nmodel DPRChainage {\n  id Int @id @default(autoincrement())\n\n  dpr_id Int\n  dpr    DPR @relation(fields: [dpr_id], references: [id], onDelete: Cascade)\n\n  site          Site_type?\n  chainage_from String?\n  chainge_to    String?\n  category_id   Int\n  category      Category   @relation(fields: [category_id], references: [id], onDelete: Cascade)\n\n  activity_id Int\n  activity    Activity @relation(fields: [activity_id], references: [id], onDelete: Cascade)\n\n  material_id Int?\n  material    Material? @relation(fields: [material_id], references: [id], onDelete: Cascade)\n\n  number Int?\n  length Int?\n  width  Int?\n  depth  Int?\n\n  unit_id Int\n  unit    Unit @relation(fields: [unit_id], references: [id], onDelete: Cascade)\n\n  quantity         Int?\n  plan_quantity    Int?\n  work_description String?\n  boq_rate         Int?\n  amount           Int?\n\n  created_at DateTime  @default(now())\n  updated_at DateTime  @updatedAt\n  images     DPRFile[]\n\n  @@index([dpr_id])\n  @@map(\"dpr_chainages\")\n}\n\nmodel DPRFile {\n  id      Int @id @default(autoincrement())\n  dpr_id  Int\n  file_id Int\n\n  file File        @relation(fields: [file_id], references: [id], onDelete: Cascade)\n  dpr  DPRChainage @relation(fields: [dpr_id], references: [id], onDelete: Cascade)\n\n  @@unique([dpr_id, file_id])\n  @@map(\"dpr_files\")\n}\n\nenum ReceiptStatus {\n  RECEIVED\n  ACCEPTED\n  REJECTED\n  PARTIALLY_ACCEPTED\n  PENDING\n}\n\nmodel GRN {\n  id Int @id @default(autoincrement())\n\n  po_id             Int\n  gate_entry_number String?\n  vehicle_number    String?\n  driver_name       String?\n  driver_contact    String?\n\n  transport_mode TransportMode?\n  status         ReceiptStatus\n  received_date  DateTime\n  received_time  String?\n\n  store_location String?\n\n  quality_check_completed Boolean @default(false)\n  grn_remarks             String?\n\n  material_receipts GRNMaterialReceipt[]\n  purchase_order    PO                   @relation(fields: [po_id], references: [id], onDelete: Cascade)\n  created_by_id     Int?\n  created_by        User?                @relation(fields: [created_by_id], references: [id], onDelete: Cascade)\n  created_at        DateTime             @default(now())\n  updated_at        DateTime             @updatedAt\n  grnfiles          GRNFile[]\n  invoiceItems      InvoiceItem[]\n\n  @@index([po_id])\n  @@map(\"grn\")\n}\n\nmodel GRNMaterialReceipt {\n  id Int @id @default(autoincrement())\n\n  grn_id      Int\n  material_id Int\n  ordered     Int\n  chainage    String?\n  quality     String? // Good / Damaged / Failed Test etc.\n  accepted    Int\n  rejected    Int\n  received    Int\n  grn         GRN      @relation(fields: [grn_id], references: [id], onDelete: Cascade)\n  material    Material @relation(fields: [material_id], references: [id])\n\n  created_at DateTime @default(now())\n\n  invoiceItems InvoiceItem[]\n\n  @@map(\"grn_matrial_receipt\")\n}\n\nmodel GRNFile {\n  id Int @id @default(autoincrement())\n\n  grn_id  Int\n  file_id Int\n\n  grn  GRN  @relation(fields: [grn_id], references: [id], onDelete: Cascade)\n  file File @relation(fields: [file_id], references: [id], onDelete: Cascade)\n\n  @@unique([grn_id, file_id])\n  @@map(\"grn_file\")\n}\n\nenum POStatus {\n  DRAFT\n  ISSUED\n  PARTIALLY_DELIVERED\n  DELIVERED\n  CANCELLED\n  CLOSED\n}\n\nenum TransportMode {\n  ROAD\n  RAIL\n  SEA\n  AIR\n  SELF_PICKUP\n}\n\nmodel PO {\n  id Int @id @default(autoincrement())\n\n  pr_id      Int\n  project_id Int\n  vendor_id  Int\n\n  po_code                String    @unique\n  po_date                DateTime  @default(now())\n  expected_delivery_date DateTime?\n\n  transport_mode TransportMode?\n\n  total_amount String\n  gst_percent  String?\n  gst_amount   String?\n\n  po_status POStatus @default(DRAFT)\n\n  payment_terms  String?\n  delivery_terms String?\n\n  shipping_address String?\n  billing_address  String?\n\n  remarks String?\n\n  order_items             POOrderItem[]\n  pr                      PR                       @relation(fields: [pr_id], references: [id])\n  project                 Project                  @relation(fields: [project_id], references: [id])\n  vendor                  Vendor                   @relation(fields: [vendor_id], references: [id])\n  created_at              DateTime                 @default(now())\n  updated_at              DateTime                 @updatedAt\n  grns                    GRN[]\n  vendorSupplyManagements VendorSupplyManagement[]\n  invoices                Invoice[]\n\n  @@index([pr_id])\n  @@index([project_id])\n  @@index([vendor_id])\n  @@map(\"pos\")\n}\n\nmodel POOrderItem {\n  id Int @id @default(autoincrement())\n\n  po_id       Int\n  material_id Int\n\n  quantity String\n  rate     String\n  amount   String\n  hsn_no   String?\n\n  po       PO       @relation(fields: [po_id], references: [id], onDelete: Cascade)\n  material Material @relation(fields: [material_id], references: [id])\n\n  created_at DateTime @default(now())\n\n  @@map(\"po_order_items\")\n}\n\nenum PRStatus {\n  DRAFT // PR created but not submitted\n  SUBMITTED // PR submitted by requester\n  INVENTORY_CHECK // Inventory manager checking availability\n  PARTIAL_AVAILABLE // Some items available, some not\n  PROCUREMENT_REQUIRED // At least one item not available → procurement needed\n  APPROVED // Approved for issue / purchase\n  REJECTED\n  CLOSED // Fully issued (after stock / purchase)\n}\n\nenum UrgencyLevel {\n  LOW\n  MEDIUM\n  HIGH\n  CRITICAL\n}\n\nenum PRType {\n  INVENTORY // Material issued directly from stock\n  PROCUREMENT // Material not available → purchase required\n  NONE // Default value\n}\n\nmodel PR {\n  id            Int          @id @default(autoincrement())\n  project_id    Int\n  pr_code       String       @unique\n  pr_type       PRType       @default(NONE)\n  urgency_level UrgencyLevel\n  status        PRStatus     @default(DRAFT)\n\n  remarks String?\n\n  user_id       Int? // Created by\n  approved_by   Int? // Approver (User ID)\n  send_to       Int?\n  user          User? @relation(\"CreatedBy\", fields: [user_id], references: [id])\n  approval_user User? @relation(\"approvalUser\", fields: [send_to], references: [id])\n  approvedUser  User? @relation(\"ApprovedBy\", fields: [approved_by], references: [id])\n\n  material_items PRMaterialItem[]\n  project        Project          @relation(fields: [project_id], references: [id])\n  created_at     DateTime         @default(now())\n  updated_at     DateTime         @updatedAt\n  pos            PO[]\n  prgrns         PRGRN[]\n\n  @@index([project_id])\n  @@index([user_id])\n  @@map(\"prs\")\n}\n\nmodel PRMaterialItem {\n  id    Int @id @default(autoincrement())\n  pr_id Int\n\n  material_id      Int\n  quantity         String\n  required_date    DateTime\n  is_approved      Boolean  @default(false)\n  approved_qty     String?\n  approval_remarks String?\n\n  pr       PR       @relation(fields: [pr_id], references: [id], onDelete: Cascade)\n  material Material @relation(fields: [material_id], references: [id])\n\n  created_at DateTime @default(now())\n\n  @@map(\"pr_material_items\")\n}\n\nmodel Activity {\n  id                 Int                  @id @default(autoincrement())\n  name               String\n  unit_id            Int\n  unit               Unit                 @relation(fields: [unit_id], references: [id])\n  category_id        Int\n  category           Category             @relation(fields: [category_id], references: [id])\n  createdAt          DateTime             @default(now())\n  updatedAt          DateTime             @updatedAt\n  materials          Material[]\n  dprchainages       DPRChainage[]\n  materialBoqItems   MaterialBoqItem[]\n  workScopeItems     WorkScopeItem[]\n  dieselConsumptions diesel_consumption[]\n\n  @@map(\"activities\")\n}\n\nmodel Category {\n  id                Int                @id @default(autoincrement())\n  name              String\n  description       String?\n  createdAt         DateTime           @default(now())\n  updatedAt         DateTime           @updatedAt\n  activities        Activity[]\n  materials         Material[]\n  dprchainages      DPRChainage[]\n  materialBoqItems  MaterialBoqItem[]\n  workScopeItems    WorkScopeItem[]\n  projectCategories project_category[]\n\n  @@map(\"categories\")\n}\n\nmodel Chainage_consumption_ledger {\n  id            Int      @id @default(autoincrement())\n  chainage_data Json\n  projectId     Int\n  project       Project  @relation(fields: [projectId], references: [id])\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  @@map(\"chainage_consumption_ledger\")\n}\n\nenum DieselTransactionType {\n  DIESEL_RECEIPT\n  DIESEL_ISSUE\n}\n\nmodel DieselTransaction {\n  id Int @id @default(autoincrement())\n\n  transaction_type DieselTransactionType\n\n  date       DateTime\n  project_id Int\n\n  /**\n   * -------- Diesel Receipt Fields --------\n   */\n  vendor_id      Int?\n  invoice_number String?\n  quantity       String? // in litres\n  rate_per_litre String?\n  total_amount   String?\n\n  /**\n   * -------- Diesel Issue Fields --------\n   */\n  equipment_name       String?\n  vehicle_number       String?\n  purpose              String?\n  issue_rate_per_litre String?\n  remarks              String?\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n  vendor     Vendor?  @relation(fields: [vendor_id], references: [id])\n  project    Project  @relation(fields: [project_id], references: [id])\n\n  @@index([project_id])\n  @@index([transaction_type])\n  @@map(\"diesel_transactions\")\n}\n\nmodel diesel_consumption {\n  id                 Int      @id @default(autoincrement())\n  machine_id         Int\n  activity_id        Int\n  diesel_used_liters Int\n  hours_used         Int\n  operator_name      String\n  date               DateTime\n  issued_by          Int\n  remarks            String\n  machine            Machine  @relation(fields: [machine_id], references: [id])\n  activity           Activity @relation(fields: [activity_id], references: [id])\n  user               User     @relation(fields: [issued_by], references: [id])\n  created_at         DateTime @default(now())\n  updated_at         DateTime @updatedAt\n\n  @@map(\"diesel_consumption\")\n}\n\nmodel DieselSupplier {\n  id             Int    @id @default(autoincrement())\n  name           String\n  contact_number String\n  address        String\n\n  diesel_inwards DieselInward[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"diesel_supplier\")\n}\n\nmodel DieselInward {\n  id Int @id @default(autoincrement())\n\n  supplier_id     Int\n  supplier        DieselSupplier @relation(fields: [supplier_id], references: [id])\n  state           String\n  district        String\n  pincode         String\n  quantity_litres Float\n  rate_per_litre  Float\n  total_amount    Float\n\n  delivery_person_name String?\n  vehicle_number       String?\n  assigned_to          Int\n  assigned             User     @relation(fields: [assigned_to], references: [id])\n  received_by          String\n  received_at          DateTime\n  invoiceNumber        String?\n  remarks              String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"diesel_inward\")\n}\n\nmodel DieselStock {\n  id                      Int    @id @default(autoincrement())\n  state                   String\n  district                String\n  pincode                 String\n  current_quantity_litres Float\n  tank_capacity_litres    Float?\n  manager_id              Int\n  manager                 User   @relation(fields: [manager_id], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"diesel_stock\")\n}\n\nmodel File {\n  id           Int      @id @default(autoincrement())\n  filename     String\n  originalName String\n  mimeType     String\n  size         Int\n  filePath     String\n  fileContent  Bytes\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  users           User[]\n  dprfiles        DPRFile[]\n  grnfiles        GRNFile[]\n  vendorDocuments VendorDocuments[]\n\n  prgrnfiles   PRGRNFile[]\n  projectFiles ProjectFile[]\n\n  @@map(\"files\")\n}\n\nmodel Invoice {\n  id Int @id @default(autoincrement())\n\n  invoiceNumber String   @unique\n  invoiceDate   DateTime\n\n  invoiceType       String // TAX_INVOICE\n  reverseCharge     Boolean @default(false)\n  currency          String  @default(\"INR\")\n  // 🔗 CORE LINK\n  po_id             Int\n  sellerId          Int\n  consigneeId       Int?\n  taxDetailId       Int?\n  amountSummaryId   Int?\n  transportDetailId Int?\n  auditDetailId     Int?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // 🔗 RELATIONS\n  po        PO      @relation(fields: [po_id], references: [id])\n  seller    Vendor  @relation(\"seller\", fields: [sellerId], references: [id])\n  buyer     String?\n  consignee Vendor? @relation(\"consignee\", fields: [consigneeId], references: [id])\n\n  taxDetail       TaxDetail?\n  amountSummary   InvoiceAmountSummary?\n  transportDetail TransportDetail?\n  auditDetail     InvoiceAudit?\n\n  items                  InvoiceItem[]\n  invoiceAmountSummaryId Int?\n  invoiceAuditId         Int?\n  user                   User?         @relation(fields: [userId], references: [id])\n  userId                 Int?\n\n  @@map(\"invoice\")\n}\n\nmodel InvoiceItem {\n  id Int @id @default(autoincrement())\n\n  invoiceId               Int\n  grn_id                  Int\n  grn_material_receipt_id Int\n\n  basicAmount          Float?\n  taxableValue         Float?\n  freightRatePerUnit   Float?\n  unloadingRatePerUnit Float?\n\n  invoice Invoice            @relation(fields: [invoiceId], references: [id])\n  grn     GRN                @relation(fields: [grn_id], references: [id])\n  grnItem GRNMaterialReceipt @relation(fields: [grn_material_receipt_id], references: [id])\n\n  @@index([grn_id])\n  @@map(\"invoice_item\")\n}\n\nmodel TaxDetail {\n  id Int @id @default(autoincrement())\n\n  cgstRate   Float?\n  cgstAmount Float?\n\n  sgstRate   Float?\n  sgstAmount Float?\n\n  igstRate   Float?\n  igstAmount Float?\n\n  totalTax Float?\n\n  invoice   Invoice? @relation(fields: [invoiceId], references: [id])\n  invoiceId Int?     @unique\n\n  @@map(\"tax_detail\")\n}\n\nmodel InvoiceAmountSummary {\n  id Int @id @default(autoincrement())\n\n  goodsValue   Float?\n  taxableValue Float?\n\n  freightAmount   Float?\n  unloadingAmount Float?\n\n  roundOff Float?\n\n  totalTaxAmount    Float?\n  totalInvoiceValue Float?\n\n  amountInWords String\n\n  invoice   Invoice? @relation(fields: [invoiceId], references: [id])\n  invoiceId Int?     @unique\n\n  @@map(\"invoice_amount_summary\")\n}\n\nmodel TransportDetail {\n  id Int @id @default(autoincrement())\n\n  transporterName  String\n  transporterGstin String?\n\n  vehicleNumber String?\n  wagonNumber   String?\n\n  transportMode String // ROAD / RAIL\n  lrRrNo        String?\n  lrRrDate      DateTime?\n\n  dispatchFrom String?\n  destination  String?\n  distanceKm   Int?\n\n  invoice   Invoice? @relation(fields: [invoiceId], references: [id])\n  invoiceId Int?     @unique\n\n  @@map(\"transport_detail\")\n}\n\nmodel InvoiceAudit {\n  id Int @id @default(autoincrement())\n\n  preparedBy   String?\n  checkedBy    String?\n  authorizedBy String?\n\n  declaration     String?\n  termsConditions String?\n\n  invoice   Invoice? @relation(fields: [invoiceId], references: [id])\n  invoiceId Int?     @unique\n\n  @@map(\"invoice_audit\")\n}\n\nenum LabourStatus {\n  ACTIVE\n  INACTIVE\n  LEFT\n  BLACKLISTED\n}\n\nenum LabourType {\n  DIRECT\n  CONTRACT\n}\n\nmodel Labour {\n  id Int @id @default(autoincrement())\n\n  labour_name String\n  labour_code String @unique\n\n  labour_type LabourType\n  skill       String\n\n  phone_number  String?\n  aadhar_number String? @unique\n  address       String?\n\n  joining_date DateTime?\n  status       LabourStatus @default(ACTIVE)\n\n  created_at        DateTime           @default(now())\n  updated_at        DateTime           @updatedAt\n  labourAttendances LabourAttendance[]\n\n  @@index([labour_type])\n  @@index([status])\n  @@map(\"labours\")\n}\n\nenum AttendanceStatus {\n  PRESENT\n  ABSENT\n  HALF_DAY\n  ON_LEAVE\n}\n\nmodel LabourAttendance {\n  id String @id @default(uuid())\n\n  labour_id  Int\n  project_id Int\n\n  date           DateTime  @db.Date\n  check_in_time  DateTime?\n  check_out_time DateTime?\n\n  total_working_hours Float?\n  field_working_hours Float? // actual hours worked on site\n  overtime_hours      Float?\n\n  status AttendanceStatus\n\n  chainage_from String?\n  chainage_to   String?\n\n  remarks String?\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  // Relations (optional but recommended)\n  labour  Labour  @relation(fields: [labour_id], references: [id])\n  project Project @relation(fields: [project_id], references: [id])\n\n  @@index([labour_id, date])\n  @@index([project_id])\n  @@map(\"labour_attendance\")\n}\n\nmodel Machine {\n  id                 Int                  @id @default(autoincrement())\n  name               String\n  type               String\n  is_owned           Boolean              @default(false)\n  rent_per_hour      String?\n  purchase_cost      String?\n  created_at         DateTime             @default(now())\n  updated_at         DateTime             @updatedAt\n  dieselConsumptions diesel_consumption[]\n\n  @@map(\"machines\")\n}\n\nmodel Material {\n  id                    Int                    @id @default(autoincrement())\n  name                  String\n  material_code         String?                @unique\n  activityId            Int?\n  unitId                Int?\n  categoryId            Int?\n  createdAt             DateTime               @default(now())\n  updatedAt             DateTime               @updatedAt\n  activity              Activity?              @relation(fields: [activityId], references: [id])\n  unit                  Unit?                  @relation(fields: [unitId], references: [id])\n  category              Category?              @relation(fields: [categoryId], references: [id])\n  prmaterialItems       PRMaterialItem[]\n  poorderItems          POOrderItem[]\n  grnmaterialReceipts   GRNMaterialReceipt[]\n  stocks                Stock[]\n  prgrnmaterialReceipts PRGRNMaterialReceipt[]\n  dprchainages          DPRChainage[]\n  materialBoqItems      MaterialBoqItem[]\n  workScopeItems        WorkScopeItem[]\n\n  @@map(\"materials\")\n}\n\nmodel MaterialBoq {\n  id                      Int                         @id @default(autoincrement())\n  project_id              Int\n  project                 Project                     @relation(fields: [project_id], references: [id])\n  createdAt               DateTime                    @default(now())\n  updatedAt               DateTime                    @updatedAt\n  materialBoqItems        MaterialBoqItem[]\n  subContractorWorkOrders sub_contractor_work_order[]\n\n  @@map(\"material_boq\")\n}\n\nmodel MaterialBoqItem {\n  id              Int         @id @default(autoincrement())\n  material_boq_id Int\n  material_boq    MaterialBoq @relation(fields: [material_boq_id], references: [id])\n  item_no         String?\n\n  material_id        Int?\n  material           Material?          @relation(fields: [material_id], references: [id])\n  unit_id            Int\n  unit               Unit               @relation(fields: [unit_id], references: [id])\n  activity_id        Int\n  activity           Activity           @relation(fields: [activity_id], references: [id])\n  category_id        Int?\n  category           Category?          @relation(fields: [category_id], references: [id])\n  item_description   String?\n  scope_quantity     Float?\n  purchased_quantity Float?\n  balanced_quantity  Float?\n  rate               Float?\n  createdAt          DateTime           @default(now())\n  updatedAt          DateTime           @updatedAt\n  workOrderItems     work_order_items[]\n\n  @@map(\"material_boq_item\")\n}\n\nmodel Module {\n  id          Int          @id @default(autoincrement())\n  Name        String\n  description String?\n  permissions Permission[] @relation(\"PermissionModules\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"modules\")\n}\n\nmodel Permission {\n  id          Int      @id @default(autoincrement())\n  action      String[]\n  modules     Module[] @relation(\"PermissionModules\")\n  roles       Role[]   @relation(\"RolePermissions\")\n  title       String?\n  description String?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@map(\"permissions\")\n}\n\nmodel PRGRN {\n  id Int @id @default(autoincrement())\n\n  pr_id             Int\n  gate_entry_number String?\n  vehicle_number    String?\n  driver_name       String?\n  driver_contact    String?\n\n  transport_mode          TransportMode?\n  status                  ReceiptStatus\n  received_date           DateTime\n  received_time           String?\n  quality_check_completed Boolean        @default(false)\n  grn_remarks             String?\n\n  material_receipts PRGRNMaterialReceipt[]\n  purchase_request  PR                     @relation(fields: [pr_id], references: [id], onDelete: Cascade)\n  created_by_id     Int?\n  created_by        User?                  @relation(fields: [created_by_id], references: [id], onDelete: Cascade)\n\n  created_at DateTime    @default(now())\n  updated_at DateTime    @updatedAt\n  grnfiles   PRGRNFile[]\n\n  @@index([pr_id])\n  @@map(\"pr_grns\")\n}\n\nmodel PRGRNMaterialReceipt {\n  id Int @id @default(autoincrement())\n\n  grn_id      Int\n  material_id Int\n  ordered     Int\n  chainage    String?\n  quality     String?\n  accepted    Int\n  rejected    Int\n  received    Int\n  grn         PRGRN    @relation(fields: [grn_id], references: [id], onDelete: Cascade)\n  material    Material @relation(fields: [material_id], references: [id])\n\n  created_at DateTime @default(now())\n\n  @@map(\"pr_grn_material_receipt\")\n}\n\nmodel PRGRNFile {\n  id Int @id @default(autoincrement())\n\n  grn_id  Int\n  file_id Int\n\n  grn  PRGRN @relation(fields: [grn_id], references: [id], onDelete: Cascade)\n  file File  @relation(fields: [file_id], references: [id], onDelete: Cascade)\n\n  @@unique([grn_id, file_id])\n  @@map(\"pr_grn_files\")\n}\n\n// enum ProjectType {\n//     HAM\n//     EPC\n//     BOT\n//     OTHER\n// }\n\nenum ProjectStatus {\n  PLANNED\n  IN_PROGRESS\n  ON_HOLD\n  COMPLETED\n  CANCELLED\n}\n\nmodel Project {\n  id              Int          @id @default(autoincrement())\n  project_type_id Int?\n  project_type    ProjectType? @relation(fields: [project_type_id], references: [id], onDelete: Cascade)\n  project_name    String\n  project_code    String\n  start_date      DateTime?\n  end_date        DateTime?\n\n  budget String?\n  status ProjectStatus @default(PLANNED)\n\n  client          String?\n  description     String?\n  progress        Int? // 0–100 %\n  manager_id      Int?\n  project_manager User?               @relation(fields: [manager_id], references: [id])\n  district        String?\n  state           String?\n  pincode         String?\n  from_length     String?\n  to_length       String?\n  total_length    String?\n  total_chainage  String[]\n  ham_details     HAMSpecificDetails?\n  epc_details     EPCSpecificDetails?\n  bot_details     BOTSpecificDetails?\n  other_details   Json?\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  directSupplyConfigurations DirectSupplyConfiguration[]\n  chainageConsumptionLedgers Chainage_consumption_ledger[]\n  prs                        PR[]\n  pos                        PO[]\n  dieselTransactions         DieselTransaction[]\n  dprs                       DPR[]\n\n  labourAttendances LabourAttendance[]\n\n  project_files           ProjectFile[]\n  materialBoqs            MaterialBoq[]\n  workScopes              WorkScope[]\n  subContractorWorkOrders sub_contractor_work_order[]\n  projectCategories       project_category[]\n\n  @@map(\"project\")\n}\n\nmodel HAMSpecificDetails {\n  id         Int @id @default(autoincrement())\n  project_id Int @unique\n\n  annuity_amount             String?\n  annuity_period             Int? // in years\n  construction_period        Int? // in months\n  maintenance_responsibility String?\n  progress                   Int? // 0–100 %\n\n  project Project @relation(fields: [project_id], references: [id], onDelete: Cascade)\n\n  @@map(\"ham_specific_details\")\n}\n\nmodel EPCSpecificDetails {\n  id         Int @id @default(autoincrement())\n  project_id Int @unique\n\n  engineering_scope     String?\n  procurement_budget    String?\n  construction_timeline String?\n  performance_guarantee String?\n  progress              Int? // 0–100 %\n\n  project Project @relation(fields: [project_id], references: [id], onDelete: Cascade)\n\n  @@map(\"epc_specific_details\")\n}\n\nmodel BOTSpecificDetails {\n  id                              Int     @id @default(autoincrement())\n  project_id                      Int     @unique\n  concession_period               Int? // in years\n  estimated_operating_cost        String? // per year\n  toll_revenue_collection_enabled Boolean @default(false)\n  transfer_condition              String?\n\n  project Project @relation(fields: [project_id], references: [id], onDelete: Cascade)\n\n  @@map(\"bot_specific_details\")\n}\n\nmodel ProjectFile {\n  id         Int     @id @default(autoincrement())\n  project_id Int\n  project    Project @relation(fields: [project_id], references: [id], onDelete: Cascade)\n  file_id    Int\n  file       File    @relation(fields: [file_id], references: [id], onDelete: Cascade)\n\n  @@map(\"project_file\")\n}\n\nmodel project_category {\n  id          Int      @id @default(autoincrement())\n  project_id  Int\n  project     Project  @relation(fields: [project_id], references: [id], onDelete: Cascade)\n  category_id Int\n  category    Category @relation(fields: [category_id], references: [id], onDelete: Cascade)\n\n  @@map(\"project_category\")\n}\n\nmodel ProjectType {\n  id          Int       @id @default(autoincrement())\n  name        String\n  description String?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n  projects    Project[]\n\n  @@map(\"project_types\")\n}\n\nmodel Role {\n  id          Int     @id @default(autoincrement())\n  name        String  @unique\n  description String?\n  users       User[]\n\n  permissions Permission[] @relation(\"RolePermissions\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"roles\")\n}\n\n// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Looking for ways to speed up your queries, or scale easily with your serverless or edge functions?\n// Try Prisma Accelerate: https://pris.ly/cli/accelerate-init\n// mcxc\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../../src/generated/client\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nenum Provider {\n  credentials\n  google\n}\n\nenum StockStatus {\n  IN_STOCK\n  LOW_STOCK\n  OUT_OF_STOCK\n  RESERVED\n  DAMAGED\n  DISPOSED\n}\n\nmodel Stock {\n  id                         Int         @id @default(autoincrement())\n  material_id                Int\n  pincode                    String\n  state                      String\n  district                   String\n  status                     StockStatus @default(IN_STOCK)\n  minimum_threshold_quantity Int?\n  current_stock              Int?\n  quantity                   Int?\n  specifications             String?\n  manager_id                 Int\n  inventory_manager          User        @relation(fields: [manager_id], references: [id])\n  createdAt                  DateTime    @default(now())\n  updatedAt                  DateTime    @updatedAt\n  material                   Material?   @relation(fields: [material_id], references: [id])\n\n  @@map(\"stock\")\n}\n\nenum work_order_status {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nenum payment_status {\n  PENDING\n  PAID\n  PARTIALLY_PAID\n}\n\nmodel sub_contractor_work_order {\n  id                     Int                @id @default(autoincrement())\n  project_id             Int\n  vendor_id              Int\n  materia_boq_id         Int\n  work_order_no          String\n  work_order_date        DateTime\n  work_order_status      work_order_status?\n  work_order_description String?\n  work_order_amount      String?\n  meta_data              Json?\n  payment_status         payment_status     @default(PENDING)\n  project                Project            @relation(fields: [project_id], references: [id])\n  vendor                 Vendor             @relation(fields: [vendor_id], references: [id])\n  material_boq           MaterialBoq        @relation(fields: [materia_boq_id], references: [id])\n  created_at             DateTime           @default(now())\n  updated_at             DateTime           @updatedAt\n  workOrderItems         work_order_items[]\n\n  @@map(\"sub_contractor_work_order\")\n}\n\nmodel work_order_items {\n  id                   Int                       @id @default(autoincrement())\n  work_order_id        Int\n  material_boq_item_id Int\n  material_boq_item    MaterialBoqItem           @relation(fields: [material_boq_item_id], references: [id])\n  work_order           sub_contractor_work_order @relation(fields: [work_order_id], references: [id], onDelete: Cascade)\n  created_at           DateTime                  @default(now())\n  updated_at           DateTime                  @updatedAt\n\n  @@map(\"work_order_items\")\n}\n\nmodel Unit {\n  id               Int               @id @default(autoincrement())\n  name             String\n  createdAt        DateTime          @default(now())\n  updatedAt        DateTime          @updatedAt\n  materials        Material[]\n  activities       Activity[]\n  dprchainages     DPRChainage[]\n  materialBoqItems MaterialBoqItem[]\n  workScopeItems   WorkScopeItem[]\n\n  @@map(\"units\")\n}\n\nmodel User {\n  id                Int      @id @default(autoincrement())\n  name              String\n  email             String   @unique\n  emailVerified     Boolean  @default(false)\n  password          String\n  fileId            Int?\n  profileImage      File?    @relation(fields: [fileId], references: [id])\n  original_password String?\n  mobileNumber      String?\n  roleId            Int?\n  role              Role?    @relation(fields: [roleId], references: [id])\n  createdAt         DateTime @default(now())\n  updatedAt         DateTime @updatedAt\n  provider          Provider @default(credentials)\n  dprs              DPR[]\n  prs_created_by    PR[]     @relation(\"CreatedBy\")\n\n  prs_approved_by PR[] @relation(\"ApprovedBy\")\n\n  projects Project[]\n\n  prs PR[] @relation(\"approvalUser\")\n\n  invoices Invoice[]\n\n  prgrns PRGRN[]\n\n  grns               GRN[]\n  stocks             Stock[]\n  dieselStocks       DieselStock[]\n  dieselInwards      DieselInward[]\n  dieselConsumptions diesel_consumption[]\n\n  @@map(\"users\")\n}\n\nenum VendorStatus {\n  ACTIVE\n  INACTIVE\n  SUSPENDED\n}\n\nenum VendorType {\n  SUB_CONTRACTOR\n  MATERIAL_SUPPLIER\n}\n\nmodel Vendor {\n  id Int @id @default(autoincrement())\n\n  // Vendor Details\n  vendor_name        String\n  proprietor_name    String?\n  contact_person     String?\n  contact_number     String\n  email_address      String?\n  address            String\n  registered_address String?\n\n  vendor_type VendorType?\n  status      VendorStatus @default(ACTIVE)\n\n  bankDetails      VendorBankDetails?\n  financialDetails VendorFinancialDetails?\n  otherDetails     VendorOtherDetails?\n  documents        VendorDocuments[]\n\n  supplies           VendorSupplyManagement[]\n  pos                PO[]\n  dieselTransactions DieselTransaction[]\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  invoice_seller Invoice[] @relation(\"seller\")\n\n  invoice_consignee       Invoice[]                   @relation(\"consignee\")\n  subContractorWorkOrders sub_contractor_work_order[]\n\n  @@map(\"vendor\")\n}\n\nmodel VendorBankDetails {\n  id       Int @id @default(autoincrement())\n  vendorId Int @unique\n\n  bank_name           String\n  branch_name         String?\n  bank_address        String?\n  bank_contact_number String?\n\n  account_number String\n  ifsc_code      String\n  micr_code      String?\n  rtgs_code      String?\n  neft_code      String?\n\n  vendor Vendor @relation(fields: [vendorId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"vendor_bank_details\")\n}\n\nmodel VendorFinancialDetails {\n  id       Int @id @default(autoincrement())\n  vendorId Int @unique\n\n  registration_number String?\n  pan_number          String\n  esi_number          String?\n  pf_number           String?\n  gst_number          String?\n  gst_state           String?\n\n  annual_turnover       String?\n  audited_balance_years String?\n  yearly_work_capacity  String?\n\n  vendor Vendor @relation(fields: [vendorId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"vendor_financial_details\")\n}\n\nmodel VendorOtherDetails {\n  id       Int @id @default(autoincrement())\n  vendorId Int @unique\n\n  organization_type   String?\n  total_team_size     String?\n  plant_and_machinery String?\n  organization_chart  String?\n\n  interested_other_work String?\n  association_status    String?\n  geographical_presence String?\n  major_clients         String?\n\n  sop_qap_signoff     String?\n  sop_quality_manual  String?\n  relative_experience String?\n\n  vendor Vendor @relation(fields: [vendorId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"vendor_other_details\")\n}\n\nmodel VendorDocuments {\n  id            Int     @id @default(autoincrement())\n  vendorId      Int\n  file_id       Int?\n  document_type String?\n\n  vendor    Vendor   @relation(fields: [vendorId], references: [id], onDelete: Cascade)\n  file      File?    @relation(fields: [file_id], references: [id], onDelete: Cascade)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"vendor_documents\")\n}\n\nenum SupplyStatus {\n  PENDING // PO created, supply not started\n  APPROVED // Approved for dispatch\n  IN_TRANSIT // Vendor dispatched material\n  PARTIALLY_RECEIVED\n  RECEIVED // Fully received\n  REJECTED\n}\n\nenum SupplyType {\n  TO_INVENTORY\n  DIRECT_TO_SITE\n}\n\nmodel VendorSupplyManagement {\n  id Int @id @default(autoincrement())\n\n  vendor_id               Int\n  supply_type             SupplyType\n  po_id                   Int?\n  amount                  String\n  payment_terms           String?\n  status                  SupplyStatus                  @default(PENDING)\n  direct_supply_config    DirectSupplyConfiguration?\n  inventory_supply_config InventorySupplyConfiguration?\n  vendor                  Vendor                        @relation(fields: [vendor_id], references: [id], onDelete: Cascade)\n  po                      PO?                           @relation(fields: [po_id], references: [id], onDelete: Cascade)\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  @@map(\"vendor_supply_management\")\n}\n\nmodel DirectSupplyConfiguration {\n  id                Int     @id @default(autoincrement())\n  supply_id         Int     @unique\n  project_id        Int\n  chainage_location String?\n  delivery_location String?\n  fob_destination   String?\n\n  supply  VendorSupplyManagement @relation(fields: [supply_id], references: [id], onDelete: Cascade)\n  project Project                @relation(fields: [project_id], references: [id], onDelete: Cascade)\n\n  @@map(\"direct_supply_configuration\")\n}\n\nmodel InventorySupplyConfiguration {\n  id                     Int       @id @default(autoincrement())\n  supply_id              Int       @unique\n  warehouse_location     String?\n  expected_delivery_date DateTime?\n  batch_number           String?\n  quality_check_status   String? // Accepted / Rejected / Pending\n\n  supply VendorSupplyManagement @relation(fields: [supply_id], references: [id], onDelete: Cascade)\n\n  @@map(\"inventory_supply_configuration\")\n}\n\nmodel WorkScope {\n  id             Int             @id @default(autoincrement())\n  project_id     Int\n  project        Project         @relation(fields: [project_id], references: [id])\n  createdAt      DateTime        @default(now())\n  updatedAt      DateTime        @updatedAt\n  workScopeItems WorkScopeItem[]\n\n  @@map(\"workscope\")\n}\n\nmodel WorkScopeItem {\n  id           Int       @id @default(autoincrement())\n  workscope_id Int\n  workscope    WorkScope @relation(fields: [workscope_id], references: [id])\n  material_id  Int\n  material     Material  @relation(fields: [material_id], references: [id])\n  unit_id      Int\n  unit         Unit      @relation(fields: [unit_id], references: [id])\n  activity_id  Int\n  activity     Activity  @relation(fields: [activity_id], references: [id])\n  category_id  Int\n  category     Category  @relation(fields: [category_id], references: [id])\n  length       Int?\n  executed     Float?\n  quantity     Float?\n  balanced     Float?\n  createdAt    DateTime  @default(now())\n  updatedAt    DateTime  @updatedAt\n\n  @@map(\"workscope_item\")\n}\n"
}

